import json
import os
import sys
import time
from pathlib import Path

HOOKS_DIR = str(Path(__file__).parent.parent.parent.parent / "hooks")
sys.path.insert(0, HOOKS_DIR)
from lib.allowlist import match_sentinel_grant_for_write, SENTINEL_GRANT_DIR

AC_UID = "ac1-write-scoped-grant-allows-named-file"
AC_TYPE = "hook"


def _write_sentinel(task_id, session_id, ops, ttl=300):
    os.makedirs(SENTINEL_GRANT_DIR, exist_ok=True)
    path = os.path.join(SENTINEL_GRANT_DIR, f"{task_id}.json")
    now = time.time()
    grant = {"task_id": task_id, "session_id": session_id,
             "allowed_operations": ops, "created_at": now, "expires_at": now + ttl}
    with open(path, "w") as f:
        json.dump(grant, f)
    return path


def test_AC1():
    """
    GIVEN: a valid sentinel with allowed_operations containing {"op":"Write","target":"/tmp/allowed.json"} and correct session_id
    WHEN:  match_sentinel_grant_for_write(task_id, session_id, "/tmp/allowed.json") is called
    THEN:  the function returns a non-None dict with op=="Write" and target=="/tmp/allowed.json"
    """
    task_id, session_id = "gen-ac1-write-allows", "gen-ac1-session"
    path = _write_sentinel(task_id, session_id, [{"op": "Write", "target": "/tmp/allowed.json"}])
    try:
        result = match_sentinel_grant_for_write(task_id, session_id, "/tmp/allowed.json")
        assert result is not None, "Expected non-None for matching target"
        assert result.get("op") == "Write"
        assert result.get("target") == "/tmp/allowed.json"
    finally:
        if os.path.exists(path):
            os.unlink(path)
